import{c as e,bn as a,aU as r,aX as d,w as l,a1 as n}from"./chunks/framework.BZ6QiwKG.js";const m=JSON.parse('{"title":"洛湮","description":"","frontmatter":{"order":5},"headers":[],"relativePath":"地图/幽冥血海/洛湮.md","filePath":"地图/幽冥血海/洛湮.md","lastUpdated":0}'),h={name:"地图/幽冥血海/洛湮.md"};function i(s,t,o,b,c,x){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="洛湮" tabindex="-1">洛湮 <a class="header-anchor" href="#洛湮" aria-label="Permalink to “洛湮”">​</a></h1><h2 id="小怪掉落" tabindex="-1">小怪掉落 <a class="header-anchor" href="#小怪掉落" aria-label="Permalink to “小怪掉落”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">木类材料</th><th style="text-align:center;">矿类材料</th><th style="text-align:center;">布类材料</th></tr></thead><tbody><tr><td style="text-align:center;">焦枯木</td><td style="text-align:center;">玄虚砂</td><td style="text-align:center;">暮云绢</td></tr></tbody></table><h2 id="罗酆谷" tabindex="-1">罗酆谷 <a class="header-anchor" href="#罗酆谷" aria-label="Permalink to “罗酆谷”">​</a></h2><h3 id="土伯" tabindex="-1">土伯 <a class="header-anchor" href="#土伯" aria-label="Permalink to “土伯”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>普通攻击：用拳头朝前方地面重砸一击，土伯血量较低时，重砸后紧接着会连续再砸击三下，最后再接一击重击</td></tr><tr><td>颤地俯冲：原地爆起后跳向玩家，在玩家头顶时开始缓慢下落，随后砸地。土伯血量较低时，砸地后在落地点周围延迟发生地震，造成额外伤害</td></tr><tr><td>所向披靡：身体前倾朝前冲锋，起手踏步并逐渐加速，在撞墙之前冲锋不会结束。土伯血量较低时，撞墙后立刻取消僵直，短暂蓄力反击一拳</td></tr><tr><td>绳缚八方：向四周伸出多根绳子再收回，捆绑触碰到的敌人并聚在身前，随后在自身位置轰出蓄力一拳，被命中的敌人会陷入混乱</td></tr><tr><td>被动：土伯每次释放“颤地俯冲” 都会在地上留下一个异界印记<br>异涌迸发：触发所有异界印记，向上迸发幽冥能量</td></tr><tr><td>制胜反击：土伯摆出招架姿态迎敌，若成功招架则会晕眩攻击者并进入反击阶段，瞬移至玩家上空，斜向朝目标飞踢，践踏地面</td></tr><tr><td>场景互动：场景正中央上方束缚着一根镇魂钉，土伯每使用“所向披靡”撞击墙壁都会使封印松动，直到束缚被解除时镇魂钉会落下砸地，被镇魂钉砸中的目标会受到巨量伤害，玩家也可以通过普攻敲打墙壁加速下落</td></tr></tbody></table><p>掉落道具：洛湮防具制作书</p><h2 id="九泉" tabindex="-1">九泉 <a class="header-anchor" href="#九泉" aria-label="Permalink to “九泉”">​</a></h2><h3 id="摆渡冥将" tabindex="-1">摆渡冥将 <a class="header-anchor" href="#摆渡冥将" aria-label="Permalink to “摆渡冥将”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>场景buff：处于水下会获得中毒效果（处于水中越久，中毒效果越强）</td></tr><tr><td>冥气冲击：朝敌人方向打出冥气</td></tr><tr><td>长杆扫空：长杆奋力朝前方横扫上扬，将敌人击飞</td></tr><tr><td>水域龙卷：撑船向前移动，而后其他区域下方向上生成水柱，持续一段时间伤害</td></tr><tr><td>长杆破浪：将长杆横扫一圈击退敌人，而后长杆奋力插入水中，向两侧生成多道水浪</td></tr><tr><td>水浪翻涌：朝水下施法，从水底向上掀起多道水流</td></tr><tr><td>冥光庇佑：生成光芒护盾笼罩自身（期间boss不受攻击），护盾结束以后，冥灯释放能量给boss回血一次（护盾期间受到的伤害越多，回血越多）</td></tr></tbody></table><p>掉落道具：洛湮武器制作书（第一心法）</p><h2 id="九泉隐藏" tabindex="-1">九泉隐藏 <a class="header-anchor" href="#九泉隐藏" aria-label="Permalink to “九泉隐藏”">​</a></h2><p>使用普通攻击，将所有前方的灯调整至与后方相同，开启<strong>隐藏入口</strong></p><img src="'+l+'" alt="九泉隐藏" style="zoom:67%;"><h3 id="九渊鬼王" tabindex="-1">九渊鬼王 <a class="header-anchor" href="#九渊鬼王" aria-label="Permalink to “九渊鬼王”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>普通攻击：向上或向下高速旋转，快速上升或下降，切割路径上的敌人</td></tr><tr><td>渊影游龙：高速旋转自身形成螺旋水龙卷，在水中朝玩家方向连续快速穿梭，对碰到的敌人造成伤害，最后再挥舞双叉封杀敌人</td></tr><tr><td>涛卷残云：高速旋转海叉，召唤一个横跨全屏的水龙卷，封锁敌人的行动</td></tr><tr><td>怒渊狂潮：生成一团暗流，暗流短暂搅动后会发射水波，推动玩家移动</td></tr><tr><td>水幕泉涌：短暂预警后，在下方沙地处召唤连续爆起的能量水柱，水柱命中后会施加破甲效果。引爆结束后会留下一条气泡路径，随后路径底端升起一颗超级水泡，命中敌人或上升至顶端后水球爆炸造成伤害</td></tr><tr><td>冥渊护咒：召唤3只九渊冥兵从下方沙土中破土而出，冥兵会朝鬼王簇拥并守护在鬼王周围，敌人靠近时冥兵会主动攻击。鬼王施咒保护他与他的子民，使攻击他们的敌人短暂堕入精神深渊，无法动弹</td></tr></tbody></table><p>掉落道具：洛湮武器制作书（第二心法）</p><h2 id="业火莲台" tabindex="-1">业火莲台 <a class="header-anchor" href="#业火莲台" aria-label="Permalink to “业火莲台”">​</a></h2><h3 id="北方鬼帝" tabindex="-1">北方鬼帝 <a class="header-anchor" href="#北方鬼帝" aria-label="Permalink to “北方鬼帝”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>北方鬼帝-张衡处于场景左侧，北方鬼帝杨云处于场景右侧，两者共享血量<br>开场张衡和杨云，一个获得抵挡状态，一个获得复活状态，每隔7秒，两个boss会交换状态<br>抵挡状态：受到的伤害降低<br>复活状态：鬼帝死亡后会复活，血量回到20%，最多复活2次</td></tr><tr><td>冥火噬魂：杨云朝敌人方向释放一道冥火攻击敌人；张衡展开书卷，向上浮现1个“鬼”字飞往敌人</td></tr><tr><td>冥火雷袭：杨云抬起冥灯，从敌人头顶落下冥火，伤害并沉默敌人；张衡摇晃书卷，从敌人头顶降下落雷，伤害敌人</td></tr><tr><td>石裂震波：张衡摇晃书卷，控制场景上的地动仪的龙珠落入金蟾口中，对应方位的石板变为上下震裂状态（处于地板上会受到伤害）；杨云将身后的酒瓶扔出，控制酒瓶攻击敌人</td></tr><tr><td>电鬼冥击：张衡展开书卷，召唤多道闪电，伤害并晕眩敌人；杨云挥动冥灯，召唤多道冥火激光，伤害敌人</td></tr><tr><td>落雷破晓：张衡持续摇动书卷，杨云持续挥动冥灯，召唤全屏落雷造成高额伤害（处于红莲火盾中可免疫伤害）</td></tr></tbody></table><p>掉落道具：洛湮阴鬼令制作书</p><h2 id="法宝" tabindex="-1">法宝 <a class="header-anchor" href="#法宝" aria-label="Permalink to “法宝”">​</a></h2><h3 id="洛湮浑天仪" tabindex="-1">洛湮浑天仪 <a class="header-anchor" href="#洛湮浑天仪" aria-label="Permalink to “洛湮浑天仪”">​</a></h3><img src="'+n+'" alt="洛湮浑天仪" style="zoom:50%;"><table tabindex="0"><thead><tr><th style="text-align:center;">被动</th><th style="text-align:center;">属性</th></tr></thead><tbody><tr><td style="text-align:center;">回血</td><td style="text-align:center;">19~26</td></tr><tr><td style="text-align:center;">回魔</td><td style="text-align:center;">12~16</td></tr><tr><td style="text-align:center;">吸血</td><td style="text-align:center;">15~21</td></tr><tr><td style="text-align:center;">反伤</td><td style="text-align:center;">15~21</td></tr></tbody></table>',25)])])}const _=e(h,[["render",i]]);export{m as __pageData,_ as default};
